    /// [128] Wenn es sich um eine Ablesung handelt, welche keine Ablesung aufgrund der Änderung an der Messtechnik oder deren Konfiguration ist (z.B. Kundenablesung).
    // REVIEW: A regular reading (e.g. Kundenablesung) is distinguished from a meter-change reading by the absence of DTM+60 (Ausführungs-/Änderungszeitpunkt) in the same SG10. DTM+9 presence confirms it is a reading at all; DTM+60 absence confirms it is not due to a meter/config change. Group path SG9→SG10 matches MSCONS LIN-group context; fallback to message-wide if no navigator. (medium confidence)
    fn evaluate_128(&self, ctx: &EvaluationContext) -> ConditionResult {
        // True when SG10 has a reading date (DTM+9, Ablesedatum) but no device change timestamp (DTM+60),
        // indicating a regular reading not caused by meter change or configuration change
        ctx.any_group_has_qualifier_without("DTM", 0, "9", "DTM", 0, "60", &["SG9", "SG10"])
    }

    /// [129] Wenn es sich um eine Ablesung aufgrund der Änderung an der Messtechnik oder deren Konfiguration handelt (z.B. Gerätewechsel).
    // REVIEW: A meter-change reading is identified by the co-occurrence of DTM+9 (Ablesedatum) and DTM+60 (Ausführungs-/Änderungszeitpunkt) within the same SG10 instance. Uses direct navigator iteration to check co-occurrence within a single group instance (any_group_has_co_occurrence would have ambiguity for same-tag different qualifiers). Falls back to message-wide check without navigator. (medium confidence)
    fn evaluate_129(&self, ctx: &EvaluationContext) -> ConditionResult {
        // True when SG10 contains both DTM+9 (Ablesedatum) and DTM+60 (Ausführungs-/Änderungszeitpunkt),
        // indicating a reading caused by a meter change or configuration change (e.g. Gerätewechsel)
        let nav = match ctx.navigator() {
            Some(n) => n,
            None => {
                let has9 = ctx.has_qualifier("DTM", 0, "9");
                let has60 = ctx.has_qualifier("DTM", 0, "60");
                return match (has9, has60) {
                    (ConditionResult::True, ConditionResult::True) => ConditionResult::True,
                    (ConditionResult::Unknown, _) | (_, ConditionResult::Unknown) => {
                        ConditionResult::Unknown
                    }
                    _ => ConditionResult::False,
                };
            }
        };
        let sg10_count = nav.group_instance_count(&["SG9", "SG10"]);
        for i in 0..sg10_count {
            let dtms = nav.find_segments_in_group("DTM", &["SG9", "SG10"], i);
            let has9 = dtms.iter().any(|s| {
                s.elements
                    .first()
                    .and_then(|e| e.first())
                    .is_some_and(|v| v == "9")
            });
            let has60 = dtms.iter().any(|s| {
                s.elements
                    .first()
                    .and_then(|e| e.first())
                    .is_some_and(|v| v == "60")
            });
            if has9 && has60 {
                return ConditionResult::True;
            }
        }
        ConditionResult::False
    }

