    /// [133] Wenn innerhalb desselben LIN-Segments neben diesem Segment (SG10 DTM+7 Nutzungszeitpunkt) noch das SG10 DTM+9 (Ablesedatum) mit dem Code 102 im DE2379 vorhanden ist, darf der Wert der Differenz zwi...
    // REVIEW: Checks that when DTM+7 (Nutzungszeitpunkt, format 303 CCYYMMDDHHMM) and DTM+9 (Ablesedatum, format 102 CCYYMMDD) co-exist in the same SG10 instance, the CCYYMMDD date part of DTM+7 must equal or be at most 1 calendar day different from DTM+9. Uses a Julian Day Number formula for correct cross-month/year date arithmetic. MSCONS SG10 path assumed as SG5.SG6.SG10 based on the tx_group=SG5 and SG6 being the measurement period container; medium confidence due to path uncertainty. (medium confidence)
    fn evaluate_133(&self, ctx: &EvaluationContext) -> ConditionResult {
        let nav = match ctx.navigator() {
            Some(n) => n,
            None => return ConditionResult::Unknown,
        };
        fn date_to_days(s: &str) -> Option<i64> {
            if s.len() < 8 {
                return None;
            }
            let y: i64 = s[..4].parse().ok()?;
            let m: i64 = s[4..6].parse().ok()?;
            let d: i64 = s[6..8].parse().ok()?;
            if m < 1 || m > 12 || d < 1 || d > 31 {
                return None;
            }
            let a = (14 - m) / 12;
            let yy = y + 4800 - a;
            let mm = m + 12 * a - 3;
            Some(d + (153 * mm + 2) / 5 + 365 * yy + yy / 4 - yy / 100 + yy / 400 - 32045)
        }
        let sg10_count = nav.group_instance_count(&["SG5", "SG6", "SG10"]);
        if sg10_count == 0 {
            return ConditionResult::Unknown;
        }
        for i in 0..sg10_count {
            let dtms = nav.find_segments_in_group("DTM", &["SG5", "SG6", "SG10"], i);
            let dtm7_val = dtms
                .iter()
                .find(|s| {
                    s.elements
                        .first()
                        .and_then(|e| e.first())
                        .is_some_and(|v| v == "7")
                })
                .and_then(|s| s.elements.first())
                .and_then(|e| e.get(1))
                .cloned();
            let dtm9_val = dtms
                .iter()
                .find(|s| {
                    s.elements
                        .first()
                        .and_then(|e| e.first())
                        .is_some_and(|v| v == "9")
                        && s.elements
                            .first()
                            .and_then(|e| e.get(2))
                            .is_some_and(|v| v == "102")
                })
                .and_then(|s| s.elements.first())
                .and_then(|e| e.get(1))
                .cloned();
            let (v7, v9) = match (dtm7_val, dtm9_val) {
                (Some(v7), Some(v9)) if !v7.is_empty() && !v9.is_empty() => (v7, v9),
                _ => continue,
            };
            let date7 = if v7.len() >= 8 { &v7[..8] } else { continue };
            let date9 = if v9.len() >= 8 { &v9[..8] } else { v9.as_str() };
            let days7 = match date_to_days(date7) {
                Some(d) => d,
                None => return ConditionResult::Unknown,
            };
            let days9 = match date_to_days(date9) {
                Some(d) => d,
                None => return ConditionResult::Unknown,
            };
            let diff = (days7 - days9).abs();
            if diff > 1 {
                return ConditionResult::False;
            }
        }
        ConditionResult::True
    }

