    /// [135] Der Wert an der Stelle CCYYMMDD muss ≤ dem Wert an der Stelle CCYYMMDD im DE2380 des DTM+137 sein
    // REVIEW: Condition 135 compares the CCYYMMDD portion of a reading-date DTM against DTM+137 (Nachrichtendatum at message level). The most natural target is DTM+9 (Ablesedatum) in SG10. Both format 303 (CCYYMMDDhhmm+ZZ) and format 102 (CCYYMMDD) start with CCYYMMDD, so taking the first 8 characters works for both. DTM+137 uses format 303 so likewise the first 8 chars give the date. Lexicographic comparison of zero-padded CCYYMMDD strings is equivalent to numeric date comparison. Medium confidence because the condition description does not explicitly state which DTM qualifier it applies to; DTM+9 is the strongest candidate in the MSCONS SG10 context. (medium confidence)
    fn evaluate_135(&self, ctx: &EvaluationContext) -> ConditionResult {
        // The CCYYMMDD portion of the DTM value in the current context must be <= CCYYMMDD of DTM+137 (Nachrichtendatum).
        // Applied to DTM+9 (Ablesedatum) readings in SG10 — format 303 and 102 both start with CCYYMMDD.
        let dtm_137_segs = ctx.find_segments_with_qualifier("DTM", 0, "137");
        let threshold: String = match dtm_137_segs
            .first()
            .and_then(|s| s.elements.first())
            .and_then(|e| e.get(1))
        {
            Some(v) => v.chars().take(8).collect(),
            None => return ConditionResult::Unknown,
        };
        let dtm9_segs = ctx.find_segments_with_qualifier("DTM", 0, "9");
        if dtm9_segs.is_empty() {
            return ConditionResult::Unknown;
        }
        for dtm in &dtm9_segs {
            let val = match dtm.elements.first().and_then(|e| e.get(1)) {
                Some(v) => v,
                None => continue,
            };
            let date_part: String = val.chars().take(8).collect();
            if date_part > threshold {
                return ConditionResult::False;
            }
        }
        ConditionResult::True
    }

